import{R as e,U as t,V as n,et as r,j as i}from"./chunks/framework.C_EfTa_6.js";var a=JSON.parse(`{"title":"容器","description":"","frontmatter":{"title":"容器","order":50},"headers":[],"relativePath":"sde/container/index.md","filePath":"sde/container/index.md"}`),o={name:`sde/container/index.md`};function s(i,a,o,s,c,l){return r(),n(`div`,null,[...a[0]||=[e(`h1`,{id:`容器`,tabindex:`-1`},[t(`容器 `),e(`a`,{class:`header-anchor`,href:`#容器`,"aria-label":`Permalink to “容器”`},`​`)],-1),e(`p`,null,`容器技术通过操作系统级的虚拟化，将应用及其依赖封装为标准化的运行单元。与传统虚拟机不同，容器共享宿主机的操作系统内核，不需要模拟完整的硬件和运行完整的操作系统，因此在启动速度、资源占用和部署密度上具有显著优势。这种轻量级特性使得容器在微服务架构和持续交付场景中得到了广泛的应用。`,-1),e(`p`,null,`容器技术生态主要由三个层面构成。底层是 Linux 内核提供的隔离和控制机制，包括 Namespace 实现的视图隔离、Cgroup 实现的资源限制和 UnionFS 实现的分层文件系统。中间层是容器运行时，以 Docker 和 containerd 为代表，将内核特性封装为开发者可用的工具链。上层是容器编排平台，以 Kubernetes 为代表，解决大规模容器集群的管理、调度和服务发现等问题。`,-1),e(`p`,null,`在实际工程中，容器技术的价值不仅在于它本身，更在于它所推动的软件交付方式的变革。通过容器镜像，开发、测试和生产环境可以保持高度一致，消除了"在我机器上能运行"的问题。通过镜像仓库和编排系统，软件的部署从手工操作变为可重复、可审计的自动化流程。容器编排平台进一步将服务的扩缩容、故障恢复和滚动更新等运维操作标准化，让团队可以将精力集中在业务逻辑的实现上。`,-1)]])}var c=i(o,[[`render`,s]]);export{a as __pageData,c as default};